type LiveSession = Awaited<ReturnType<InstanceType<typeof GoogleGenAI>["live"]["connect"]>>;
import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from 'react-dom/client';

// --- FIREBASE CONFIGURATION ---
