                        scriptProcessor.onaudioprocess = (audioProcessingEvent) => {
                            if (!isSessionActive.current) return;
                            const inputData = audioProcessingEvent.inputBuffer.getChannelData(0);

                            // --- IMPROVED AUDIO PROCESSING STAGE ---
                            // 1. High Pass Filter (Remove Rumble/DC Offset)
                            // 2. Noise Gate with Hysteresis (Prevent chatter)
                            // 3. Dynamic Compression (Leveling)

                            const HPF_ALPHA = 0.90; // Cutoff ~150Hz at 16kHz to remove background rumble
                            const GATE_OPEN_THRESHOLD = 0.015; // Higher threshold to open gate (-36dB)
                            const GATE_CLOSE_THRESHOLD = 0.008; // Lower threshold to close gate (-42dB)
                            const TARGET_RMS = 0.2; 
                            const MAX_GAIN = 12.0;   
                            const ATTACK_COEFF = 0.8; 
                            const RELEASE_COEFF = 0.99; // Slow release to avoid pumping
                            const GAIN_SMOOTHING = 0.92; // Smoother gain transitions

                            // Initialize state if needed (backward compatibility)
                            if (!audioRefs.current.audioProcessingState.hpfState) {
                                audioRefs.current.audioProcessingState.hpfState = { lastInput: 0, lastOutput: 0 };
                                audioRefs.current.audioProcessingState.noiseGateOpen = false;
                            }

                            const { hpfState } = audioRefs.current.audioProcessingState;

                            // 1. Apply High Pass Filter in-place
                            // y[i] = x[i] - x[i-1] + alpha * y[i-1]
                            for (let i = 0; i < inputData.length; i++) {
                                const raw = inputData[i];
                                const filtered = raw - hpfState.lastInput + HPF_ALPHA * hpfState.lastOutput;
                                inputData[i] = filtered;
                                hpfState.lastInput = raw;
                                hpfState.lastOutput = filtered;
                            }

                            // 2. Calculate RMS of filtered signal
                            let sum = 0;
                            for (let i = 0; i < inputData.length; i++) {
                                sum += inputData[i] * inputData[i];
                            }
                            const rms = Math.sqrt(sum / inputData.length);

                            // 3. Envelope Follower
                            let { smoothedVolume, currentGain, noiseGateOpen } = audioRefs.current.audioProcessingState;

                            if (rms > smoothedVolume) {
                                smoothedVolume = ATTACK_COEFF * smoothedVolume + (1 - ATTACK_COEFF) * rms;
                            } else {
                                smoothedVolume = RELEASE_COEFF * smoothedVolume + (1 - RELEASE_COEFF) * rms;
                            }

                            // 4. Noise Gate Hysteresis
                            // Only change state if we cross the specific threshold for that direction
                            if (noiseGateOpen) {
                                if (smoothedVolume < GATE_CLOSE_THRESHOLD) {
                                    noiseGateOpen = false;
                                }
                            } else {
                                if (smoothedVolume > GATE_OPEN_THRESHOLD) {
                                    noiseGateOpen = true;
                                }
                            }

                            // --- SPEAKING TIMER LOGIC ---
                            // Use the stable noiseGateOpen state for better speech detection accuracy
                            const SILENCE_TIMEOUT = 2000; // 2 seconds

                            if (noiseGateOpen) {
                                lastSpeechDetectedTimeRef.current = Date.now();
                                if (!isUserSpeakingRef.current) {
                                    isUserSpeakingRef.current = true;
                                    speechStartTimeRef.current = Date.now();
                                }
                            } else {
                                // If silence persists longer than timeout, reset the speaking state
                                if (isUserSpeakingRef.current && (Date.now() - lastSpeechDetectedTimeRef.current > SILENCE_TIMEOUT)) {
                                    isUserSpeakingRef.current = false;
                                    speechStartTimeRef.current = null;
                                }
                            }
                            // --- END SPEAKING TIMER LOGIC ---

                            // 5. Calculate Target Gain based on Dynamic Compression
                            let targetGain = 1.0;
                            if (!noiseGateOpen) {
                                // Expander: Drop gain significantly when gate is closed (soft gate)
                                // We don't use absolute 0 to preserve a tiny bit of "room tone" naturalness if needed, 
                                // but 0.0 is safest for preventing hallucination.
                                targetGain = 0.0; 
                            } else {
