                                // Target a consistent output RMS
                                targetGain = TARGET_RMS / (smoothedVolume + 0.00001);
                                targetGain = Math.min(targetGain, MAX_GAIN);
                                targetGain = Math.max(targetGain, 1.0); // Only boost
                            }

                            // 6. Smooth the Gain Application
                            currentGain = GAIN_SMOOTHING * currentGain + (1 - GAIN_SMOOTHING) * targetGain;

                            // 7. Apply Gain & Soft Limiting
                            for (let i = 0; i < inputData.length; i++) {
                                inputData[i] *= currentGain;
                                // Soft Clipper (tanh-like approximation)
                                if (inputData[i] > 0.99) inputData[i] = 0.99;
                                if (inputData[i] < -0.99) inputData[i] = -0.99;
                            }

                            // Save state
                            audioRefs.current.audioProcessingState = { 
                                smoothedVolume, 
                                currentGain, 
                                noiseGateOpen, 
                                hpfState 
                            };
                            // --- END PROCESSING ---

