                                    <li>Switch them to <strong>Allow</strong>.</li>
                                    <li>Refresh this page.</li>
                                </ol>
                            </div>
                        ) : (
                            <p style={{ color: '#666', marginBottom: '20px' }}>
                                To simulate a real session, we need access to your microphone and camera. 
                                Video is recorded for your personal review only.
                            </p>
                        )}

                        <div className="modal-btn-group">
                            {!permissionDenied ? (
                                <>
                                    <button className="button modal-btn-secondary" onClick={() => setShowPermissionModal(false)}>Cancel</button>
                                    <button className="button" onClick={confirmPermission}>Enable Access</button>
                                </>
                            ) : (
                                <button className="button" onClick={() => window.location.reload()}>Refresh Page</button>
                            )}
                        </div>
                    </div>
                </div>
            )}

            {activeScoreModal && (
                <div className="modal-overlay" onClick={() => setActiveScoreModal(null)}>
                    <div className="modal-content max-w-md w-full mx-4" onClick={(e) => e.stopPropagation()}>
                        <div className="flex items-center justify-between mb-4 border-b pb-3 border-gray-200 dark:border-gray-700">
                             <h3 className="text-xl font-bold text-gray-900 dark:text-white m-0">
                                {getScoreTitle(activeScoreModal)}
                             </h3>
                             <button onClick={() => setActiveScoreModal(null)} className="p-1 rounded-full hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
                                <span className="material-icons text-gray-500">close</span>
                             </button>
                        </div>

                        <div className="text-left py-2">
                             <p className="text-lg text-gray-700 dark:text-gray-300 leading-relaxed">
                                {getScoreExplanation(activeScoreModal)}
                             </p>
                        </div>

                        <div className="mt-6 flex justify-end">
                            <button className="button" onClick={() => setActiveScoreModal(null)}>
                                Close
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

