    };

    const startLiveSession = async () => {
        await cleanupAudioResources();

        audioRefs.current.audioProcessingState = { 
            smoothedVolume: 0, 
            currentGain: 1.0,
            noiseGateOpen: false,
            hpfState: { lastInput: 0, lastOutput: 0 }
        };

