        if (sessionRef.current) sessionRef.current = null;
        if (audioRefs.current.mediaRecorder && audioRefs.current.mediaRecorder.state !== 'inactive') {
            try { audioRefs.current.mediaRecorder.stop(); } catch (e) {}
        }
