            if (resumeAnalysis) systemInstructionText += `\n\nCONTEXT:\n${resumeAnalysis}`;
            if (settings.mode === 'timed') systemInstructionText += `\nNOTE: Timed session (90s).`;

            const sessionPromise = ai.live.connect({
