import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from "react-dom/client";
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

type SessionType = 'interview' | 'seminar' | 'presentation';

interface Settings {
    role: string;
    topics: string;
    language: string;
}

// --- Helper Functions ---

const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            const base64 = result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = (error) => reject(error);
    });
};

function decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
}

function encode(bytes: Uint8Array) {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

function createBlob(data: Float32Array) {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
        int16[i] = data[i] * 32768;
    }
    return {
        data: encode(new Uint8Array(int16.buffer)),
        mimeType: 'audio/pcm;rate=16000',
    };
}

// --- Main Component ---

function App() {
    const [screen, setScreen] = useState<string>('setup'); // setup, briefing, interview
    const [loadingAction, setLoadingAction] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    // Setup State
    const [sessionType, setSessionType] = useState<SessionType>('interview');
    const [settings, setSettings] = useState<Settings>({
        role: 'Software Engineer',
        topics: 'System Design',
        language: 'English',
    });
    const [resumeFile, setResumeFile] = useState<File | null>(null);
    const [resumeAnalysis, setResumeAnalysis] = useState<string>('');

    // Briefing State
    const [briefingText, setBriefingText] = useState<string>('');

    // Session State
    const [transcript, setTranscript] = useState<Array<{speaker: 'user' | 'ai', text: string}>>([]);
    const [isMuted, setIsMuted] = useState(false);
    const [isAiSpeaking, setIsAiSpeaking] = useState(false);

    // Refs for Audio & Logic
    const sessionRef = useRef<any>(null);
    const isSessionActive = useRef(false);
    const isAiSpeakingRef = useRef(false);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const transcriptEndRef = useRef<HTMLDivElement>(null);

    const transcriptionBuffer = useRef({ input: '', output: '' });

    const audioRefs = useRef<{
        inputAudioContext: AudioContext | null;
        outputAudioContext: AudioContext | null;
        stream: MediaStream | null;
        scriptProcessor: ScriptProcessorNode | null;
        source: MediaStreamAudioSourceNode | null;
    }>({
        inputAudioContext: null,
        outputAudioContext: null,
        stream: null,
        scriptProcessor: null,
        source: null,
    });

    // --- Effects ---

    useEffect(() => {
        // Auto-scroll transcript
        if (transcriptEndRef.current) {
            transcriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [transcript]);

    // --- Cleanup ---

    const cleanupAudioResources = async () => {
        isSessionActive.current = false;
        isAiSpeakingRef.current = false;
        setIsAiSpeaking(false);

        if (sessionRef.current) {
             sessionRef.current = null;
        }

        if (audioRefs.current.scriptProcessor) {
            try { audioRefs.current.scriptProcessor.disconnect(); } catch(e) {}
            audioRefs.current.scriptProcessor = null;
        }
        if (audioRefs.current.source) {
            try { audioRefs.current.source.disconnect(); } catch(e) {}
            audioRefs.current.source = null;
        }
        if (audioRefs.current.stream) {
            audioRefs.current.stream.getTracks().forEach(track => track.stop());
            audioRefs.current.stream = null;
        }
        if (audioRefs.current.inputAudioContext) {
            try { await audioRefs.current.inputAudioContext.close(); } catch(e) {}
            audioRefs.current.inputAudioContext = null;
        }
        if (audioRefs.current.outputAudioContext) {
            try { await audioRefs.current.outputAudioContext.close(); } catch(e) {}
            audioRefs.current.outputAudioContext = null;
        }
    };

    // --- Handlers ---

    const handleGenerateBriefing = async () => {
        setLoadingAction(resumeFile ? 'analyzing_file' : 'generating_briefing');
        setError(null);
        setBriefingText('');

        let currentResumeAnalysis = '';

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            if (resumeFile) {
                try {
                    const base64Data = await fileToBase64(resumeFile);
                    let resumePrompt = "";
                    if (sessionType === 'interview') {
                         resumePrompt = "You are an expert technical interviewer. Analyze this candidate's resume. Extract the candidate's name (if available), key technical skills, detailed work history, and specifically the details of any projects mentioned. Provide a structured summary that an interviewer can use to ask specific, deep-dive questions about their actual experience. Focus on what they built, technologies used, and their specific role.";
                    } else {
                         resumePrompt = "You are an expert presentation coach and fact-checker. Analyze these slides/document. Extract a structured list of KEY FACTS, DATA POINTS, DEFINITIONS, and MAIN ARGUMENTS. I need to use this to fact-check the presenter in real-time if they say something wrong. Also summarize the intended narrative flow.";
                    }

                    const resumeResponse = await ai.models.generateContent({
                        model: 'gemini-3-flash-preview',
                        contents: {
                            parts: [
                                { inlineData: { mimeType: 'application/pdf', data: base64Data } },
                                { text: resumePrompt }
                            ]
                        }
                    });
                    currentResumeAnalysis = resumeResponse.text || '';
                    setResumeAnalysis(currentResumeAnalysis);
                } catch (resumeErr: any) {
                    console.error("File analysis failed", resumeErr);
                }
            }

            setLoadingAction('generating_briefing');
            let textPrompt = "";
            if (sessionType === 'interview') {
                textPrompt = `Generate a short, friendly, and professional welcome message for a job interview. The role is '${settings.role}' and the topics are '${settings.topics}'. Welcome the candidate, state the role and topics, and wish them luck. The message must be entirely in ${settings.language}.`;
                if (currentResumeAnalysis) {
                    textPrompt += `\n\nContext: The candidate has uploaded a resume. Here is the summary: ${currentResumeAnalysis}. Acknowledge that you have reviewed their resume and mention that you will be asking questions about their projects.`;
                }
            } else {
                textPrompt = `Generate a short, encouraging welcome message for a ${sessionType === 'seminar' ? 'seminar' : 'presentation'} practice session. The user is presenting on '${settings.role}' to an audience of '${settings.topics}'. Welcome them, acknowledge you have reviewed their materials (if any), and ask them to begin their presentation whenever they are ready. State that you will listen actively and interrupt ONLY if you hear a factual error based on their slides. The message must be entirely in ${settings.language}.`;
                if (currentResumeAnalysis) {
                    textPrompt += `\n\nContext: The user has uploaded slides. Summary: ${currentResumeAnalysis}.`;
                }
            }

            const textResponse = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: textPrompt,
            });
            setBriefingText(textResponse.text || '');
            setLoadingAction(null);
            setScreen('briefing');

        } catch (err: any) {
            console.error("Error:", err);
            setError(err.message);
            setLoadingAction(null);
        }
    };

    const handleStartLiveSession = async () => {
        setScreen('interview');
        setLoadingAction('connecting');
        setError(null);
        setTranscript([]);

        await cleanupAudioResources();

        isSessionActive.current = true;
        isAiSpeakingRef.current = false;
        transcriptionBuffer.current = { input: '', output: '' };

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Audio Contexts
            audioRefs.current.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            audioRefs.current.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

            // Stream Setup
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
            audioRefs.current.stream = stream;

            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            // System Instructions
            let systemInstructionText = sessionType === 'interview' ? 
                `You are a Senior HR + Technical Interviewer. Role: '${settings.role}'. Focus: '${settings.topics}'. Language: ${settings.language}.
                RULES: Ask ONE question at a time. Wait for the user to answer. Provide feedback only if needed, then move to the next question.
                STAGES: Introduction, Experience Check, Technical Questions, Behavioral Questions.` :
                `You are a Presentation Coach. Topic: '${settings.role}'. Audience: '${settings.topics}'. Language: ${settings.language}.
                GOAL: Listen to the user's presentation. Only interrupt if there is a factual error or if clarity is lost. Otherwise, provide a summary at the end.`;

            if (resumeAnalysis) systemInstructionText += `\n\nCONTEXT FROM RESUME/DOCS:\n${resumeAnalysis}`;

            const sessionPromise = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        if (!isSessionActive.current) return;
                        setLoadingAction(null);

                        // Input Processing
                        const ctx = audioRefs.current.inputAudioContext;
                        if (!ctx) return;

                        const source = ctx.createMediaStreamSource(stream);
                        const scriptProcessor = ctx.createScriptProcessor(4096, 1, 1);

                        scriptProcessor.onaudioprocess = (e) => {
                            if (!isSessionActive.current) return;

                            // Mute input if AI is speaking to prevent echo
                            if (isAiSpeakingRef.current) {
                                return;
                            }

                            const inputData = e.inputBuffer.getChannelData(0);
                            const pcmBlob = createBlob(inputData);

                            sessionPromise.then(session => {
                                session.sendRealtimeInput({ media: pcmBlob });
                            });
                        };

                        source.connect(scriptProcessor);
                        scriptProcessor.connect(ctx.destination);

                        audioRefs.current.source = source;
                        audioRefs.current.scriptProcessor = scriptProcessor;
                    },
                    onmessage: async (msg: LiveServerMessage) => {
                        if (!isSessionActive.current) return;

                        // Transcription
                        if (msg.serverContent?.inputTranscription) {
                            transcriptionBuffer.current.input += msg.serverContent.inputTranscription.text;
                        }
                        if (msg.serverContent?.outputTranscription) {
                            transcriptionBuffer.current.output += msg.serverContent.outputTranscription.text;
                        }

                        if (msg.serverContent?.turnComplete) {
                            const inText = transcriptionBuffer.current.input.trim();
                            const outText = transcriptionBuffer.current.output.trim();

                            if (inText) setTranscript(prev => [...prev, { speaker: 'user', text: inText }]);
                            if (outText) setTranscript(prev => [...prev, { speaker: 'ai', text: outText }]);

                            transcriptionBuffer.current = { input: '', output: '' };
                        }

                        // Audio Output
                        const base64Audio = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (base64Audio && audioRefs.current.outputAudioContext) {
                            const ctx = audioRefs.current.outputAudioContext;
                            const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);

                            const source = ctx.createBufferSource();
                            source.buffer = audioBuffer;
                            source.connect(ctx.destination);

                            source.onended = () => {
                                setIsAiSpeaking(false);
                                isAiSpeakingRef.current = false;
                            };

                            setIsAiSpeaking(true);
                            isAiSpeakingRef.current = true;
                            source.start();
                        }
                    },
                    onclose: () => {
                        console.log("Session closed");
                    },
                    onerror: (err) => {
                        console.error("Session error", err);
                        setError("Connection error");
                    }
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                    outputAudioTranscription: {},
                    systemInstruction: systemInstructionText,
                }
            });

            sessionRef.current = await sessionPromise;

        } catch (e: any) {
            console.error(e);
            setError(e.message);
            setLoadingAction(null);
        }
    };

    const handleEndSession = async () => {
        await cleanupAudioResources();
        setScreen('setup');
    };

    // --- Render ---

    return (
        <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-blue-100">
            {/* Header */}
            <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
                <div className="flex items-center gap-2">
                    <span className="material-symbols-outlined text-blue-600 text-3xl">psychology</span>
                    <h1 className="text-xl font-bold tracking-tight text-gray-800">SpeakEasy AI</h1>
                </div>
                {screen === 'interview' && (
                    <button 
                        onClick={handleEndSession}
                        className="px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium transition-colors"
                    >
                        End Session
                    </button>
                )}
            </header>

            <main className="max-w-5xl mx-auto px-6 py-8">
                {error && (
                    <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg flex items-center gap-2">
                        <span className="material-symbols-outlined text-sm">error</span>
                        {error}
                    </div>
                )}

                {screen === 'setup' && (
                    <div className="max-w-xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
                        <h2 className="text-2xl font-semibold mb-6 text-gray-800">New Session</h2>

                        <div className="space-y-5">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['interview', 'presentation', 'seminar'].map(t => (
                                        <button 
                                            key={t}
                                            onClick={() => setSessionType(t as SessionType)}
                                            className={`py-2 px-3 rounded-lg text-sm font-medium capitalize border transition-all ${
                                                sessionType === t 
                                                ? 'bg-blue-600 text-white border-blue-600 shadow-md' 
                                                : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                                            }`}
                                        >
                                            {t}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Target Role / Subject</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    value={settings.role}
                                    onChange={(e) => setSettings({...settings, role: e.target.value})}
                                    placeholder="e.g. Senior React Developer"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Topics / Audience</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    value={settings.topics}
                                    onChange={(e) => setSettings({...settings, topics: e.target.value})}
                                    placeholder="e.g. System Design, scalability"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Resume / Materials (PDF)</label>
                                <div className="relative">
                                    <input 
                                        type="file" 
                                        accept="application/pdf"
                                        onChange={(e) => setResumeFile(e.target.files ? e.target.files[0] : null)}
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 transition-all border border-gray-300 rounded-lg"
                                    />
                                </div>
                            </div>

                            <button 
                                onClick={handleGenerateBriefing}
                                disabled={!!loadingAction}
                                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold shadow-md hover:shadow-lg transition-all flex justify-center items-center gap-2 mt-4"
                            >
                                {loadingAction ? (
                                    <>
                                        <span className="material-symbols-outlined animate-spin text-xl">progress_activity</span>
                                        Processing...
                                    </>
                                ) : (
                                    <>Start Preparation</>
                                )}
                            </button>
                        </div>
                    </div>
                )}

                {screen === 'briefing' && (
                    <div className="max-w-2xl mx-auto">
                        <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100 mb-6">
                            <h2 className="text-2xl font-semibold mb-4 text-gray-800 flex items-center gap-2">
                                <span className="material-symbols-outlined text-blue-500">article</span>
                                Session Briefing
                            </h2>
                            <div className="prose prose-blue max-w-none text-gray-600 leading-relaxed whitespace-pre-wrap">
                                {briefingText}
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <button 
                                onClick={() => setScreen('setup')}
                                className="flex-1 py-3 px-6 bg-white border border-gray-300 text-gray-700 rounded-xl font-medium hover:bg-gray-50 transition-colors"
                            >
                                Back
                            </button>
                            <button 
                                onClick={handleStartLiveSession}
                                className="flex-1 py-3 px-6 bg-blue-600 text-white rounded-xl font-semibold shadow-md hover:bg-blue-700 hover:shadow-lg transition-all flex items-center justify-center gap-2"
                            >
                                <span className="material-symbols-outlined">mic</span>
                                Start Live Session
                            </button>
                        </div>
                    </div>
                )}

                {screen === 'interview' && (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-140px)]">
                        {/* Left Column: Video & Status */}
                        <div className="lg:col-span-2 flex flex-col gap-6">
                            <div className="relative bg-black rounded-2xl overflow-hidden shadow-lg aspect-video flex items-center justify-center group">
                                <video 
                                    ref={videoRef} 
                                    autoPlay 
                                    playsInline 
                                    muted 
                                    className={`w-full h-full object-cover transform scale-x-[-1] transition-opacity ${isMuted ? 'opacity-90' : 'opacity-100'}`}
                                />

                                <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                                    <div className="flex gap-2">
                                         <div className={`px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1.5 backdrop-blur-md ${isAiSpeaking ? 'bg-green-500/90 text-white' : 'bg-gray-800/60 text-gray-300'}`}>
                                            <span className={`w-2 h-2 rounded-full ${isAiSpeaking ? 'bg-white animate-pulse' : 'bg-gray-400'}`}></span>
                                            {isAiSpeaking ? 'AI Speaking' : 'Listening...'}
                                        </div>
                                    </div>

                                    <div className="flex gap-2">
                                        <button 
                                            onClick={() => setIsMuted(!isMuted)}
                                            className={`p-3 rounded-full backdrop-blur-md transition-all ${isMuted ? 'bg-red-500/90 text-white' : 'bg-white/20 text-white hover:bg-white/30'}`}
                                        >
                                            <span className="material-symbols-outlined">{isMuted ? 'mic_off' : 'mic'}</span>
                                        </button>
                                    </div>
                                </div>
                            </div>

                            {loadingAction === 'connecting' && (
                                <div className="flex items-center justify-center p-12 bg-white rounded-2xl border border-gray-100">
                                    <div className="text-center">
                                        <span className="material-symbols-outlined text-4xl text-blue-600 animate-spin mb-4">progress_activity</span>
                                        <p className="text-gray-500 font-medium">Connecting to AI Interviewer...</p>
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Right Column: Transcript */}
                        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 flex flex-col h-full overflow-hidden">
                            <div className="p-4 border-b border-gray-100 bg-gray-50">
                                <h3 className="font-semibold text-gray-700 flex items-center gap-2">
                                    <span className="material-symbols-outlined text-gray-400">forum</span>
                                    Live Transcript
                                </h3>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                                {transcript.length === 0 && (
                                    <p className="text-gray-400 text-sm text-center mt-10 italic">Conversation will appear here...</p>
                                )}
                                {transcript.map((msg, i) => (
                                    <div key={i} className={`flex ${msg.speaker === 'user' ? 'justify-end' : 'justify-start'}`}>
                                        <div className={`max-w-[85%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed ${
                                            msg.speaker === 'user' 
                                            ? 'bg-blue-600 text-white rounded-br-none' 
                                            : 'bg-gray-100 text-gray-800 rounded-bl-none'
                                        }`}>
                                            {msg.text}
                                        </div>
                                    </div>
                                ))}
                                <div ref={transcriptEndRef} />
                            </div>
                        </div>
                    </div>
                )}
            </main>
        </div>
    );
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from "react-dom/client";
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

type SessionType = 'interview' | 'seminar' | 'presentation';

interface Settings {
    role: string;
    topics: string;
    language: string;
}

// --- Helper Functions ---

const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            const base64 = result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = (error) => reject(error);
    });
};

function decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
}

function encode(bytes: Uint8Array) {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

function createBlob(data: Float32Array) {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
        int16[i] = data[i] * 32768;
    }
    return {
        data: encode(new Uint8Array(int16.buffer)),
        mimeType: 'audio/pcm;rate=16000',
    };
}

// --- Main Component ---

function App() {
    const [screen, setScreen] = useState<string>('setup'); // setup, briefing, interview
    const [loadingAction, setLoadingAction] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    // Setup State
    const [sessionType, setSessionType] = useState<SessionType>('interview');
    const [settings, setSettings] = useState<Settings>({
        role: 'Software Engineer',
        topics: 'System Design',
        language: 'English',
    });
    const [resumeFile, setResumeFile] = useState<File | null>(null);
    const [resumeAnalysis, setResumeAnalysis] = useState<string>('');

    // Briefing State
    const [briefingText, setBriefingText] = useState<string>('');

    // Session State
    const [transcript, setTranscript] = useState<Array<{speaker: 'user' | 'ai', text: string}>>([]);
    const [isMuted, setIsMuted] = useState(false);
    const [isAiSpeaking, setIsAiSpeaking] = useState(false);

    // Refs for Audio & Logic
    const sessionRef = useRef<any>(null);
    const isSessionActive = useRef(false);
    const isAiSpeakingRef = useRef(false);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const transcriptEndRef = useRef<HTMLDivElement>(null);

    // Audio Scheduling Refs
    const nextAudioStartTimeRef = useRef(0);
    const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

    const transcriptionBuffer = useRef({ input: '', output: '' });

    const audioRefs = useRef<{
        inputAudioContext: AudioContext | null;
        outputAudioContext: AudioContext | null;
        stream: MediaStream | null;
        scriptProcessor: ScriptProcessorNode | null;
        source: MediaStreamAudioSourceNode | null;
    }>({
        inputAudioContext: null,
        outputAudioContext: null,
        stream: null,
        scriptProcessor: null,
        source: null,
    });

    // --- Effects ---

    useEffect(() => {
        // Auto-scroll transcript
        if (transcriptEndRef.current) {
            transcriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [transcript]);

    // --- Cleanup ---

    const cleanupAudioResources = async () => {
        isSessionActive.current = false;
        isAiSpeakingRef.current = false;
        setIsAiSpeaking(false);
        nextAudioStartTimeRef.current = 0;

        // Stop all playing sources
        activeSourcesRef.current.forEach(source => {
            try { source.stop(); } catch(e) {}
        });
        activeSourcesRef.current.clear();

        if (sessionRef.current) {
             sessionRef.current = null;
        }

        if (audioRefs.current.scriptProcessor) {
            try { audioRefs.current.scriptProcessor.disconnect(); } catch(e) {}
            audioRefs.current.scriptProcessor = null;
        }
        if (audioRefs.current.source) {
            try { audioRefs.current.source.disconnect(); } catch(e) {}
            audioRefs.current.source = null;
        }
        if (audioRefs.current.stream) {
            audioRefs.current.stream.getTracks().forEach(track => track.stop());
            audioRefs.current.stream = null;
        }
        if (audioRefs.current.inputAudioContext) {
            try { await audioRefs.current.inputAudioContext.close(); } catch(e) {}
            audioRefs.current.inputAudioContext = null;
        }
        if (audioRefs.current.outputAudioContext) {
            try { await audioRefs.current.outputAudioContext.close(); } catch(e) {}
            audioRefs.current.outputAudioContext = null;
        }
    };

    // --- Handlers ---

    const handleGenerateBriefing = async () => {
        setLoadingAction(resumeFile ? 'analyzing_file' : 'generating_briefing');
        setError(null);
        setBriefingText('');

        let currentResumeAnalysis = '';

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            if (resumeFile) {
                try {
                    const base64Data = await fileToBase64(resumeFile);
                    let resumePrompt = "";
                    if (sessionType === 'interview') {
                         resumePrompt = "You are an expert technical interviewer. Analyze this candidate's resume. Extract the candidate's name (if available), key technical skills, detailed work history, and specifically the details of any projects mentioned. Provide a structured summary that an interviewer can use to ask specific, deep-dive questions about their actual experience. Focus on what they built, technologies used, and their specific role.";
                    } else {
                         resumePrompt = "You are an expert presentation coach and fact-checker. Analyze these slides/document. Extract a structured list of KEY FACTS, DATA POINTS, DEFINITIONS, and MAIN ARGUMENTS. I need to use this to fact-check the presenter in real-time if they say something wrong. Also summarize the intended narrative flow.";
                    }

                    const resumeResponse = await ai.models.generateContent({
                        model: 'gemini-3-flash-preview',
                        contents: {
                            parts: [
                                { inlineData: { mimeType: 'application/pdf', data: base64Data } },
                                { text: resumePrompt }
                            ]
                        }
                    });
                    currentResumeAnalysis = resumeResponse.text || '';
                    setResumeAnalysis(currentResumeAnalysis);
                } catch (resumeErr: any) {
                    console.error("File analysis failed", resumeErr);
                }
            }

            setLoadingAction('generating_briefing');
            let textPrompt = "";
            if (sessionType === 'interview') {
                textPrompt = `Generate a short, friendly, and professional welcome message for a job interview. The role is '${settings.role}' and the topics are '${settings.topics}'. Welcome the candidate, state the role and topics, and wish them luck. The message must be entirely in ${settings.language}.`;
                if (currentResumeAnalysis) {
                    textPrompt += `\n\nContext: The candidate has uploaded a resume. Here is the summary: ${currentResumeAnalysis}. Acknowledge that you have reviewed their resume and mention that you will be asking questions about their projects.`;
                }
            } else {
                textPrompt = `Generate a short, encouraging welcome message for a ${sessionType === 'seminar' ? 'seminar' : 'presentation'} practice session. The user is presenting on '${settings.role}' to an audience of '${settings.topics}'. Welcome them, acknowledge you have reviewed their materials (if any), and ask them to begin their presentation whenever they are ready. State that you will listen actively and interrupt ONLY if you hear a factual error based on their slides. The message must be entirely in ${settings.language}.`;
                if (currentResumeAnalysis) {
                    textPrompt += `\n\nContext: The user has uploaded slides. Summary: ${currentResumeAnalysis}.`;
                }
            }

            const textResponse = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: textPrompt,
            });
            setBriefingText(textResponse.text || '');
            setLoadingAction(null);
            setScreen('briefing');

        } catch (err: any) {
            console.error("Error:", err);
            setError(err.message);
            setLoadingAction(null);
        }
    };

    const handleStartLiveSession = async () => {
        setScreen('interview');
        setLoadingAction('connecting');
        setError(null);
        setTranscript([]);

        await cleanupAudioResources();

        isSessionActive.current = true;
        isAiSpeakingRef.current = false;
        transcriptionBuffer.current = { input: '', output: '' };
        nextAudioStartTimeRef.current = 0;

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Audio Contexts
            audioRefs.current.inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
            audioRefs.current.outputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

            // Stream Setup
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
            audioRefs.current.stream = stream;

            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            // System Instructions
            let systemInstructionText = sessionType === 'interview' ? 
                `You are a Senior HR + Technical Interviewer. Role: '${settings.role}'. Focus: '${settings.topics}'. Language: ${settings.language}.
                RULES: Ask ONE question at a time. Wait for the user to answer. Provide feedback only if needed, then move to the next question.
                STAGES: Introduction, Experience Check, Technical Questions, Behavioral Questions.` :
                `You are a Presentation Coach. Topic: '${settings.role}'. Audience: '${settings.topics}'. Language: ${settings.language}.
                GOAL: Listen to the user's presentation. Only interrupt if there is a factual error or if clarity is lost. Otherwise, provide a summary at the end.`;

            if (resumeAnalysis) systemInstructionText += `\n\nCONTEXT FROM RESUME/DOCS:\n${resumeAnalysis}`;

            const sessionPromise = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        if (!isSessionActive.current) return;
                        setLoadingAction(null);

                        // Input Processing
                        const ctx = audioRefs.current.inputAudioContext;
                        if (!ctx) return;

                        const source = ctx.createMediaStreamSource(stream);
                        const scriptProcessor = ctx.createScriptProcessor(4096, 1, 1);

                        scriptProcessor.onaudioprocess = (e) => {
                            if (!isSessionActive.current) return;

                            // Mute input if AI is speaking to prevent echo
                            if (isAiSpeakingRef.current) {
                                return;
                            }

                            const inputData = e.inputBuffer.getChannelData(0);
                            const pcmBlob = createBlob(inputData);

                            sessionPromise.then(session => {
                                session.sendRealtimeInput({ media: pcmBlob });
                            });
                        };

                        source.connect(scriptProcessor);
                        scriptProcessor.connect(ctx.destination);

                        audioRefs.current.source = source;
                        audioRefs.current.scriptProcessor = scriptProcessor;
                    },
                    onmessage: async (msg: LiveServerMessage) => {
                        if (!isSessionActive.current) return;

                        // Transcription
                        if (msg.serverContent?.inputTranscription) {
                            transcriptionBuffer.current.input += msg.serverContent.inputTranscription.text;
                        }
                        if (msg.serverContent?.outputTranscription) {
                            transcriptionBuffer.current.output += msg.serverContent.outputTranscription.text;
                        }

                        if (msg.serverContent?.turnComplete) {
                            const inText = transcriptionBuffer.current.input.trim();
                            const outText = transcriptionBuffer.current.output.trim();

                            if (inText) setTranscript(prev => [...prev, { speaker: 'user', text: inText }]);
                            if (outText) setTranscript(prev => [...prev, { speaker: 'ai', text: outText }]);

                            transcriptionBuffer.current = { input: '', output: '' };
                        }

                        // Handle Interruption
                        if (msg.serverContent?.interrupted) {
                            // Stop all currently playing audio immediately
                            activeSourcesRef.current.forEach(source => {
                                try { source.stop(); } catch(e) {}
                            });
                            activeSourcesRef.current.clear();
                            nextAudioStartTimeRef.current = 0;
                            setIsAiSpeaking(false);
                            isAiSpeakingRef.current = false;
                            return; // Stop processing this message
                        }

                        // Audio Output
                        const base64Audio = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (base64Audio && audioRefs.current.outputAudioContext) {
                            const ctx = audioRefs.current.outputAudioContext;
                            const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);

                            const source = ctx.createBufferSource();
                            source.buffer = audioBuffer;
                            source.connect(ctx.destination);

                            // Scheduling logic to prevent stutter
                            // 1. If next start time is in the past (gap in stream), reset to now.
                            // 2. Otherwise, schedule at the end of the previous chunk.
                            const startTime = Math.max(ctx.currentTime, nextAudioStartTimeRef.current);
                            source.start(startTime);
                            nextAudioStartTimeRef.current = startTime + audioBuffer.duration;

                            // Track active source
                            activeSourcesRef.current.add(source);

                            source.onended = () => {
                                activeSourcesRef.current.delete(source);
                                if (activeSourcesRef.current.size === 0) {
                                    setIsAiSpeaking(false);
                                    isAiSpeakingRef.current = false;
                                }
                            };

                            setIsAiSpeaking(true);
                            isAiSpeakingRef.current = true;
                        }
                    },
                    onclose: () => {
                        console.log("Session closed");
                    },
                    onerror: (err) => {
                        console.error("Session error", err);
                        setError("Connection error");
                    }
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                    outputAudioTranscription: {},
                    systemInstruction: systemInstructionText,
                }
            });

            sessionRef.current = await sessionPromise;

        } catch (e: any) {
            console.error(e);
            setError(e.message);
            setLoadingAction(null);
        }
    };

    const handleEndSession = async () => {
        await cleanupAudioResources();
        setScreen('setup');
    };

    // --- Render ---

    return (
        <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-blue-100">
            {/* Header */}
            <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
                <div className="flex items-center gap-2">
                    <span className="material-symbols-outlined text-blue-600 text-3xl">psychology</span>
                    <h1 className="text-xl font-bold tracking-tight text-gray-800">SpeakEasy AI</h1>
                </div>
                {screen === 'interview' && (
                    <button 
                        onClick={handleEndSession}
                        className="px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium transition-colors"
                    >
                        End Session
                    </button>
                )}
            </header>

            <main className="max-w-5xl mx-auto px-6 py-8">
                {error && (
                    <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg flex items-center gap-2">
                        <span className="material-symbols-outlined text-sm">error</span>
                        {error}
                    </div>
                )}

                {screen === 'setup' && (
                    <div className="max-w-xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
                        <h2 className="text-2xl font-semibold mb-6 text-gray-800">New Session</h2>

                        <div className="space-y-5">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['interview', 'presentation', 'seminar'].map(t => (
                                        <button 
                                            key={t}
                                            onClick={() => setSessionType(t as SessionType)}
                                            className={`py-2 px-3 rounded-lg text-sm font-medium capitalize border transition-all ${
                                                sessionType === t 
                                                ? 'bg-blue-600 text-white border-blue-600 shadow-md' 
                                                : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                                            }`}
                                        >
                                            {t}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Target Role / Subject</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    value={settings.role}
                                    onChange={(e) => setSettings({...settings, role: e.target.value})}
                                    placeholder="e.g. Senior React Developer"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Topics / Audience</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    value={settings.topics}
                                    onChange={(e) => setSettings({...settings, topics: e.target.value})}
                                    placeholder="e.g. System Design, scalability"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Resume / Materials (PDF)</label>
                                <div className="relative">
                                    <input 
                                        type="file" 
                                        accept="application/pdf"
                                        onChange={(e) => setResumeFile(e.target.files ? e.target.files[0] : null)}
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 transition-all border border-gray-300 rounded-lg"
                                    />
                                </div>
                            </div>

                            <button 
                                onClick={handleGenerateBriefing}
                                disabled={!!loadingAction}
                                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold shadow-md hover:shadow-lg transition-all flex justify-center items-center gap-2 mt-4"
                            >
                                {loadingAction ? (
                                    <>
                                        <span className="material-symbols-outlined animate-spin text-xl">progress_activity</span>
                                        Processing...
                                    </>
                                ) : (
                                    <>Start Preparation</>
                                )}
                            </button>
                        </div>
                    </div>
                )}

                {screen === 'briefing' && (
                    <div className="max-w-2xl mx-auto">
                        <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100 mb-6">
                            <h2 className="text-2xl font-semibold mb-4 text-gray-800 flex items-center gap-2">
                                <span className="material-symbols-outlined text-blue-500">article</span>
                                Session Briefing
                            </h2>
                            <div className="prose prose-blue max-w-none text-gray-600 leading-relaxed whitespace-pre-wrap">
                                {briefingText}
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <button 
                                onClick={() => setScreen('setup')}
                                className="flex-1 py-3 px-6 bg-white border border-gray-300 text-gray-700 rounded-xl font-medium hover:bg-gray-50 transition-colors"
                            >
                                Back
                            </button>
                            <button 
                                onClick={handleStartLiveSession}
                                className="flex-1 py-3 px-6 bg-blue-600 text-white rounded-xl font-semibold shadow-md hover:bg-blue-700 hover:shadow-lg transition-all flex items-center justify-center gap-2"
                            >
                                <span className="material-symbols-outlined">mic</span>
                                Start Live Session
                            </button>
                        </div>
                    </div>
                )}

                {screen === 'interview' && (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-140px)]">
                        {/* Left Column: Video & Status */}
                        <div className="lg:col-span-2 flex flex-col gap-6">
                            <div className="relative bg-black rounded-2xl overflow-hidden shadow-lg aspect-video flex items-center justify-center group">
                                <video 
                                    ref={videoRef} 
                                    autoPlay 
                                    playsInline 
                                    muted 
                                    className={`w-full h-full object-cover transform scale-x-[-1] transition-opacity ${isMuted ? 'opacity-90' : 'opacity-100'}`}
                                />

                                <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                                    <div className="flex gap-2">
                                         <div className={`px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1.5 backdrop-blur-md ${isAiSpeaking ? 'bg-green-500/90 text-white' : 'bg-gray-800/60 text-gray-300'}`}>
                                            <span className={`w-2 h-2 rounded-full ${isAiSpeaking ? 'bg-white animate-pulse' : 'bg-gray-400'}`}></span>
                                            {isAiSpeaking ? 'AI Speaking' : 'Listening...'}
                                        </div>
                                    </div>

                                    <div className="flex gap-2">
                                        <button 
                                            onClick={() => setIsMuted(!isMuted)}
                                            className={`p-3 rounded-full backdrop-blur-md transition-all ${isMuted ? 'bg-red-500/90 text-white' : 'bg-white/20 text-white hover:bg-white/30'}`}
                                        >
                                            <span className="material-symbols-outlined">{isMuted ? 'mic_off' : 'mic'}</span>
                                        </button>
                                    </div>
                                </div>
                            </div>

                            {loadingAction === 'connecting' && (
                                <div className="flex items-center justify-center p-12 bg-white rounded-2xl border border-gray-100">
                                    <div className="text-center">
                                        <span className="material-symbols-outlined text-4xl text-blue-600 animate-spin mb-4">progress_activity</span>
                                        <p className="text-gray-500 font-medium">Connecting to AI Interviewer...</p>
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Right Column: Transcript */}
                        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 flex flex-col h-full overflow-hidden">
                            <div className="p-4 border-b border-gray-100 bg-gray-50">
                                <h3 className="font-semibold text-gray-700 flex items-center gap-2">
                                    <span className="material-symbols-outlined text-gray-400">forum</span>
                                    Live Transcript
                                </h3>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                                {transcript.length === 0 && (
                                    <p className="text-gray-400 text-sm text-center mt-10 italic">Conversation will appear here...</p>
                                )}
                                {transcript.map((msg, i) => (
                                    <div key={i} className={`flex ${msg.speaker === 'user' ? 'justify-end' : 'justify-start'}`}>
                                        <div className={`max-w-[85%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed ${
                                            msg.speaker === 'user' 
                                            ? 'bg-blue-600 text-white rounded-br-none' 
                                            : 'bg-gray-100 text-gray-800 rounded-bl-none'
                                        }`}>
                                            {msg.text}
                                        </div>
                                    </div>
                                ))}
                                <div ref={transcriptEndRef} />
                            </div>
                        </div>
                    </div>
                )}
            </main>
        </div>
    );
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

import React, { useState, useRef, useEffect } from 'react';
import { createRoot } from "react-dom/client";
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

type SessionType = 'interview' | 'seminar' | 'presentation';

interface Settings {
    role: string;
    topics: string;
    language: string;
}

// --- Helper Functions ---

const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = () => {
            const result = reader.result as string;
            const base64 = result.split(',')[1];
            resolve(base64);
        };
        reader.onerror = (error) => reject(error);
    });
};

function decode(base64: string) {
    const binaryString = atob(base64);
    const len = binaryString.length;
    const bytes = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
}

function encode(bytes: Uint8Array) {
    let binary = '';
    const len = bytes.byteLength;
    for (let i = 0; i < len; i++) {
        binary += String.fromCharCode(bytes[i]);
    }
    return btoa(binary);
}

async function decodeAudioData(
    data: Uint8Array,
    ctx: AudioContext,
    sampleRate: number,
    numChannels: number,
): Promise<AudioBuffer> {
    const dataInt16 = new Int16Array(data.buffer);
    const frameCount = dataInt16.length / numChannels;
    const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

    for (let channel = 0; channel < numChannels; channel++) {
        const channelData = buffer.getChannelData(channel);
        for (let i = 0; i < frameCount; i++) {
            channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
        }
    }
    return buffer;
}

function createBlob(data: Float32Array) {
    const l = data.length;
    const int16 = new Int16Array(l);
    for (let i = 0; i < l; i++) {
        int16[i] = data[i] * 32768;
    }
    return {
        data: encode(new Uint8Array(int16.buffer)),
        mimeType: 'audio/pcm;rate=16000',
    };
}

// --- Main Component ---

function App() {
    const [screen, setScreen] = useState<string>('setup'); // setup, briefing, interview
    const [loadingAction, setLoadingAction] = useState<string | null>(null);
    const [error, setError] = useState<string | null>(null);

    // Setup State
    const [sessionType, setSessionType] = useState<SessionType>('interview');
    const [settings, setSettings] = useState<Settings>({
        role: 'Software Engineer',
        topics: 'System Design',
        language: 'English',
    });
    const [resumeFile, setResumeFile] = useState<File | null>(null);
    const [resumeAnalysis, setResumeAnalysis] = useState<string>('');

    // Briefing State
    const [briefingText, setBriefingText] = useState<string>('');

    // Session State
    const [transcript, setTranscript] = useState<Array<{speaker: 'user' | 'ai', text: string}>>([]);
    const [isMuted, setIsMuted] = useState(false);
    const [isAiSpeaking, setIsAiSpeaking] = useState(false);

    // Refs for Audio & Logic
    const sessionRef = useRef<any>(null);
    const isSessionActive = useRef(false);
    const isAiSpeakingRef = useRef(false);
    const videoRef = useRef<HTMLVideoElement | null>(null);
    const transcriptEndRef = useRef<HTMLDivElement>(null);

    // Audio Scheduling Refs
    const nextAudioStartTimeRef = useRef(0);
    const activeSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

    const transcriptionBuffer = useRef({ input: '', output: '' });

    const audioRefs = useRef<{
        inputAudioContext: AudioContext | null;
        outputAudioContext: AudioContext | null;
        outputCompressor: DynamicsCompressorNode | null;
        stream: MediaStream | null;
        scriptProcessor: ScriptProcessorNode | null;
        source: MediaStreamAudioSourceNode | null;
    }>({
        inputAudioContext: null,
        outputAudioContext: null,
        outputCompressor: null,
        stream: null,
        scriptProcessor: null,
        source: null,
    });

    // --- Effects ---

    useEffect(() => {
        // Auto-scroll transcript
        if (transcriptEndRef.current) {
            transcriptEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [transcript]);

    // --- Cleanup ---

    const cleanupAudioResources = async () => {
        isSessionActive.current = false;
        isAiSpeakingRef.current = false;
        setIsAiSpeaking(false);
        nextAudioStartTimeRef.current = 0;

        // Stop all playing sources
        activeSourcesRef.current.forEach(source => {
            try { source.stop(); } catch(e) {}
        });
        activeSourcesRef.current.clear();

        if (sessionRef.current) {
             sessionRef.current = null;
        }

        if (audioRefs.current.scriptProcessor) {
            try { audioRefs.current.scriptProcessor.disconnect(); } catch(e) {}
            audioRefs.current.scriptProcessor = null;
        }
        if (audioRefs.current.source) {
            try { audioRefs.current.source.disconnect(); } catch(e) {}
            audioRefs.current.source = null;
        }
        if (audioRefs.current.stream) {
            audioRefs.current.stream.getTracks().forEach(track => track.stop());
            audioRefs.current.stream = null;
        }
        if (audioRefs.current.inputAudioContext) {
            try { await audioRefs.current.inputAudioContext.close(); } catch(e) {}
            audioRefs.current.inputAudioContext = null;
        }
        if (audioRefs.current.outputAudioContext) {
            try { await audioRefs.current.outputAudioContext.close(); } catch(e) {}
            audioRefs.current.outputAudioContext = null;
            audioRefs.current.outputCompressor = null;
        }
    };

    // --- Handlers ---

    const handleGenerateBriefing = async () => {
        setLoadingAction(resumeFile ? 'analyzing_file' : 'generating_briefing');
        setError(null);
        setBriefingText('');

        let currentResumeAnalysis = '';

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            if (resumeFile) {
                try {
                    const base64Data = await fileToBase64(resumeFile);
                    let resumePrompt = "";
                    if (sessionType === 'interview') {
                         resumePrompt = "You are an expert technical interviewer. Analyze this candidate's resume. Extract the candidate's name (if available), key technical skills, detailed work history, and specifically the details of any projects mentioned. Provide a structured summary that an interviewer can use to ask specific, deep-dive questions about their actual experience. Focus on what they built, technologies used, and their specific role.";
                    } else {
                         resumePrompt = "You are an expert presentation coach and fact-checker. Analyze these slides/document. Extract a structured list of KEY FACTS, DATA POINTS, DEFINITIONS, and MAIN ARGUMENTS. I need to use this to fact-check the presenter in real-time if they say something wrong. Also summarize the intended narrative flow.";
                    }

                    const resumeResponse = await ai.models.generateContent({
                        model: 'gemini-3-flash-preview',
                        contents: {
                            parts: [
                                { inlineData: { mimeType: 'application/pdf', data: base64Data } },
                                { text: resumePrompt }
                            ]
                        }
                    });
                    currentResumeAnalysis = resumeResponse.text || '';
                    setResumeAnalysis(currentResumeAnalysis);
                } catch (resumeErr: any) {
                    console.error("File analysis failed", resumeErr);
                }
            }

            setLoadingAction('generating_briefing');
            let textPrompt = "";
            if (sessionType === 'interview') {
                textPrompt = `Generate a short, friendly, and professional welcome message for a job interview. The role is '${settings.role}' and the topics are '${settings.topics}'. Welcome the candidate, state the role and topics, and wish them luck. The message must be entirely in ${settings.language}.`;
                if (currentResumeAnalysis) {
                    textPrompt += `\n\nContext: The candidate has uploaded a resume. Here is the summary: ${currentResumeAnalysis}. Acknowledge that you have reviewed their resume and mention that you will be asking questions about their projects.`;
                }
            } else {
                textPrompt = `Generate a short, encouraging welcome message for a ${sessionType === 'seminar' ? 'seminar' : 'presentation'} practice session. The user is presenting on '${settings.role}' to an audience of '${settings.topics}'. Welcome them, acknowledge you have reviewed their materials (if any), and ask them to begin their presentation whenever they are ready. State that you will listen actively and interrupt ONLY if you hear a factual error based on their slides. The message must be entirely in ${settings.language}.`;
                if (currentResumeAnalysis) {
                    textPrompt += `\n\nContext: The user has uploaded slides. Summary: ${currentResumeAnalysis}.`;
                }
            }

            const textResponse = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: textPrompt,
            });
            setBriefingText(textResponse.text || '');
            setLoadingAction(null);
            setScreen('briefing');

        } catch (err: any) {
            console.error("Error:", err);
            setError(err.message);
            setLoadingAction(null);
        }
    };

    const handleStartLiveSession = async () => {
        setScreen('interview');
        setLoadingAction('connecting');
        setError(null);
        setTranscript([]);

        await cleanupAudioResources();

        isSessionActive.current = true;
        isAiSpeakingRef.current = false;
        transcriptionBuffer.current = { input: '', output: '' };
        nextAudioStartTimeRef.current = 0;

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Audio Contexts
            // NOTE: Use system default sample rate for output to avoid resampling artifacts/stuttering
            const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)();
            const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

            audioRefs.current.outputAudioContext = outputCtx;
            audioRefs.current.inputAudioContext = inputCtx;

            // Add Dynamics Compressor to Output Chain for "Radio Voice" quality
            const compressor = outputCtx.createDynamicsCompressor();
            compressor.threshold.value = -20;
            compressor.knee.value = 30;
            compressor.ratio.value = 12;
            compressor.attack.value = 0.003;
            compressor.release.value = 0.25;
            compressor.connect(outputCtx.destination);
            audioRefs.current.outputCompressor = compressor;

            // Stream Setup
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true, video: true });
            audioRefs.current.stream = stream;

            if (videoRef.current) {
                videoRef.current.srcObject = stream;
            }

            // System Instructions
            let systemInstructionText = sessionType === 'interview' ? 
                `You are a Senior HR + Technical Interviewer. Role: '${settings.role}'. Focus: '${settings.topics}'. Language: ${settings.language}.
                RULES: Ask ONE question at a time. Wait for the user to answer. Provide feedback only if needed, then move to the next question.
                STAGES: Introduction, Experience Check, Technical Questions, Behavioral Questions.` :
                `You are a Presentation Coach. Topic: '${settings.role}'. Audience: '${settings.topics}'. Language: ${settings.language}.
                GOAL: Listen to the user's presentation. Only interrupt if there is a factual error or if clarity is lost. Otherwise, provide a summary at the end.`;

            if (resumeAnalysis) systemInstructionText += `\n\nCONTEXT FROM RESUME/DOCS:\n${resumeAnalysis}`;

            const sessionPromise = ai.live.connect({
                model: 'gemini-2.5-flash-native-audio-preview-12-2025',
                callbacks: {
                    onopen: () => {
                        if (!isSessionActive.current) return;
                        setLoadingAction(null);

                        // Input Processing
                        const ctx = audioRefs.current.inputAudioContext;
                        if (!ctx) return;

                        const source = ctx.createMediaStreamSource(stream);
                        const scriptProcessor = ctx.createScriptProcessor(4096, 1, 1);

                        scriptProcessor.onaudioprocess = (e) => {
                            if (!isSessionActive.current) return;

                            // Mute input if AI is speaking to prevent echo
                            if (isAiSpeakingRef.current) {
                                return;
                            }

                            const inputData = e.inputBuffer.getChannelData(0);
                            const pcmBlob = createBlob(inputData);

                            sessionPromise.then(session => {
                                session.sendRealtimeInput({ media: pcmBlob });
                            });
                        };

                        source.connect(scriptProcessor);
                        scriptProcessor.connect(ctx.destination);

                        audioRefs.current.source = source;
                        audioRefs.current.scriptProcessor = scriptProcessor;
                    },
                    onmessage: async (msg: LiveServerMessage) => {
                        if (!isSessionActive.current) return;

                        // Transcription
                        if (msg.serverContent?.inputTranscription) {
                            transcriptionBuffer.current.input += msg.serverContent.inputTranscription.text;
                        }
                        if (msg.serverContent?.outputTranscription) {
                            transcriptionBuffer.current.output += msg.serverContent.outputTranscription.text;
                        }

                        if (msg.serverContent?.turnComplete) {
                            const inText = transcriptionBuffer.current.input.trim();
                            const outText = transcriptionBuffer.current.output.trim();

                            if (inText) setTranscript(prev => [...prev, { speaker: 'user', text: inText }]);
                            if (outText) setTranscript(prev => [...prev, { speaker: 'ai', text: outText }]);

                            transcriptionBuffer.current = { input: '', output: '' };
                        }

                        // Handle Interruption
                        if (msg.serverContent?.interrupted) {
                            // Stop all currently playing audio immediately
                            activeSourcesRef.current.forEach(source => {
                                try { source.stop(); } catch(e) {}
                            });
                            activeSourcesRef.current.clear();
                            nextAudioStartTimeRef.current = 0;
                            setIsAiSpeaking(false);
                            isAiSpeakingRef.current = false;
                            return; // Stop processing this message
                        }

                        // Audio Output
                        const base64Audio = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
                        if (base64Audio && audioRefs.current.outputAudioContext) {
                            const ctx = audioRefs.current.outputAudioContext;
                            // NOTE: 24000Hz is the raw rate from Gemini. 
                            // Creating the buffer with 24000Hz lets the browser's native AudioContext (e.g. 48000Hz)
                            // handle the resampling efficiently.
                            const audioBuffer = await decodeAudioData(decode(base64Audio), ctx, 24000, 1);

                            const source = ctx.createBufferSource();
                            source.buffer = audioBuffer;

                            // Connect to compressor for better quality
                            if (audioRefs.current.outputCompressor) {
                                source.connect(audioRefs.current.outputCompressor);
                            } else {
                                source.connect(ctx.destination);
                            }

                            // Advanced Scheduling with Jitter Buffer
                            // If we have fallen behind (current time > next start time), add a small buffer (latency)
                            // to ensure continuous playback for the incoming stream.
                            const currentTime = ctx.currentTime;
                            if (nextAudioStartTimeRef.current < currentTime) {
                                nextAudioStartTimeRef.current = currentTime + 0.05; // 50ms jitter buffer
                            }

                            source.start(nextAudioStartTimeRef.current);
                            nextAudioStartTimeRef.current += audioBuffer.duration;

                            // Track active source
                            activeSourcesRef.current.add(source);

                            source.onended = () => {
                                activeSourcesRef.current.delete(source);
                                if (activeSourcesRef.current.size === 0) {
                                    setIsAiSpeaking(false);
                                    isAiSpeakingRef.current = false;
                                }
                            };

                            setIsAiSpeaking(true);
                            isAiSpeakingRef.current = true;
                        }
                    },
                    onclose: () => {
                        console.log("Session closed");
                    },
                    onerror: (err) => {
                        console.error("Session error", err);
                        setError("Connection error");
                    }
                },
                config: {
                    responseModalities: [Modality.AUDIO],
                    inputAudioTranscription: {},
                    outputAudioTranscription: {},
                    systemInstruction: systemInstructionText,
                }
            });

            sessionRef.current = await sessionPromise;

        } catch (e: any) {
            console.error(e);
            setError(e.message);
            setLoadingAction(null);
        }
    };

    const handleEndSession = async () => {
        await cleanupAudioResources();
        setScreen('setup');
    };

    // --- Render ---

    return (
        <div className="min-h-screen bg-gray-50 text-gray-900 font-sans selection:bg-blue-100">
            {/* Header */}
            <header className="bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between shadow-sm sticky top-0 z-10">
                <div className="flex items-center gap-2">
                    <span className="material-symbols-outlined text-blue-600 text-3xl">psychology</span>
                    <h1 className="text-xl font-bold tracking-tight text-gray-800">SpeakEasy AI</h1>
                </div>
                {screen === 'interview' && (
                    <button 
                        onClick={handleEndSession}
                        className="px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium transition-colors"
                    >
                        End Session
                    </button>
                )}
            </header>

            <main className="max-w-5xl mx-auto px-6 py-8">
                {error && (
                    <div className="mb-6 bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg flex items-center gap-2">
                        <span className="material-symbols-outlined text-sm">error</span>
                        {error}
                    </div>
                )}

                {screen === 'setup' && (
                    <div className="max-w-xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-gray-100">
                        <h2 className="text-2xl font-semibold mb-6 text-gray-800">New Session</h2>

                        <div className="space-y-5">
                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
                                <div className="grid grid-cols-3 gap-2">
                                    {['interview', 'presentation', 'seminar'].map(t => (
                                        <button 
                                            key={t}
                                            onClick={() => setSessionType(t as SessionType)}
                                            className={`py-2 px-3 rounded-lg text-sm font-medium capitalize border transition-all ${
                                                sessionType === t 
                                                ? 'bg-blue-600 text-white border-blue-600 shadow-md' 
                                                : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                                            }`}
                                        >
                                            {t}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Target Role / Subject</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    value={settings.role}
                                    onChange={(e) => setSettings({...settings, role: e.target.value})}
                                    placeholder="e.g. Senior React Developer"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Topics / Audience</label>
                                <input 
                                    type="text" 
                                    className="w-full px-4 py-2 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                                    value={settings.topics}
                                    onChange={(e) => setSettings({...settings, topics: e.target.value})}
                                    placeholder="e.g. System Design, scalability"
                                />
                            </div>

                            <div>
                                <label className="block text-sm font-medium text-gray-700 mb-1">Resume / Materials (PDF)</label>
                                <div className="relative">
                                    <input 
                                        type="file" 
                                        accept="application/pdf"
                                        onChange={(e) => setResumeFile(e.target.files ? e.target.files[0] : null)}
                                        className="w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100 transition-all border border-gray-300 rounded-lg"
                                    />
                                </div>
                            </div>

                            <button 
                                onClick={handleGenerateBriefing}
                                disabled={!!loadingAction}
                                className="w-full py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold shadow-md hover:shadow-lg transition-all flex justify-center items-center gap-2 mt-4"
                            >
                                {loadingAction ? (
                                    <>
                                        <span className="material-symbols-outlined animate-spin text-xl">progress_activity</span>
                                        Processing...
                                    </>
                                ) : (
                                    <>Start Preparation</>
                                )}
                            </button>
                        </div>
                    </div>
                )}

                {screen === 'briefing' && (
                    <div className="max-w-2xl mx-auto">
                        <div className="bg-white p-8 rounded-2xl shadow-sm border border-gray-100 mb-6">
                            <h2 className="text-2xl font-semibold mb-4 text-gray-800 flex items-center gap-2">
                                <span className="material-symbols-outlined text-blue-500">article</span>
                                Session Briefing
                            </h2>
                            <div className="prose prose-blue max-w-none text-gray-600 leading-relaxed whitespace-pre-wrap">
                                {briefingText}
                            </div>
                        </div>

                        <div className="flex gap-4">
                            <button 
                                onClick={() => setScreen('setup')}
                                className="flex-1 py-3 px-6 bg-white border border-gray-300 text-gray-700 rounded-xl font-medium hover:bg-gray-50 transition-colors"
                            >
                                Back
                            </button>
                            <button 
                                onClick={handleStartLiveSession}
                                className="flex-1 py-3 px-6 bg-blue-600 text-white rounded-xl font-semibold shadow-md hover:bg-blue-700 hover:shadow-lg transition-all flex items-center justify-center gap-2"
                            >
                                <span className="material-symbols-outlined">mic</span>
                                Start Live Session
                            </button>
                        </div>
                    </div>
                )}

                {screen === 'interview' && (
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 h-[calc(100vh-140px)]">
                        {/* Left Column: Video & Status */}
                        <div className="lg:col-span-2 flex flex-col gap-6">
                            <div className="relative bg-black rounded-2xl overflow-hidden shadow-lg aspect-video flex items-center justify-center group">
                                <video 
                                    ref={videoRef} 
                                    autoPlay 
                                    playsInline 
                                    muted 
                                    className={`w-full h-full object-cover transform scale-x-[-1] transition-opacity ${isMuted ? 'opacity-90' : 'opacity-100'}`}
                                />

                                <div className="absolute bottom-4 left-4 right-4 flex justify-between items-end">
                                    <div className="flex gap-2">
                                         <div className={`px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1.5 backdrop-blur-md ${isAiSpeaking ? 'bg-green-500/90 text-white' : 'bg-gray-800/60 text-gray-300'}`}>
                                            <span className={`w-2 h-2 rounded-full ${isAiSpeaking ? 'bg-white animate-pulse' : 'bg-gray-400'}`}></span>
                                            {isAiSpeaking ? 'AI Speaking' : 'Listening...'}
                                        </div>
                                    </div>

                                    <div className="flex gap-2">
                                        <button 
                                            onClick={() => setIsMuted(!isMuted)}
                                            className={`p-3 rounded-full backdrop-blur-md transition-all ${isMuted ? 'bg-red-500/90 text-white' : 'bg-white/20 text-white hover:bg-white/30'}`}
                                        >
                                            <span className="material-symbols-outlined">{isMuted ? 'mic_off' : 'mic'}</span>
                                        </button>
                                    </div>
                                </div>
                            </div>

                            {loadingAction === 'connecting' && (
                                <div className="flex items-center justify-center p-12 bg-white rounded-2xl border border-gray-100">
                                    <div className="text-center">
                                        <span className="material-symbols-outlined text-4xl text-blue-600 animate-spin mb-4">progress_activity</span>
                                        <p className="text-gray-500 font-medium">Connecting to AI Interviewer...</p>
                                    </div>
                                </div>
                            )}
                        </div>

                        {/* Right Column: Transcript */}
                        <div className="bg-white rounded-2xl shadow-sm border border-gray-100 flex flex-col h-full overflow-hidden">
                            <div className="p-4 border-b border-gray-100 bg-gray-50">
                                <h3 className="font-semibold text-gray-700 flex items-center gap-2">
                                    <span className="material-symbols-outlined text-gray-400">forum</span>
                                    Live Transcript
                                </h3>
                            </div>
                            <div className="flex-1 overflow-y-auto p-4 space-y-4">
                                {transcript.length === 0 && (
                                    <p className="text-gray-400 text-sm text-center mt-10 italic">Conversation will appear here...</p>
                                )}
                                {transcript.map((msg, i) => (
                                    <div key={i} className={`flex ${msg.speaker === 'user' ? 'justify-end' : 'justify-start'}`}>
                                        <div className={`max-w-[85%] rounded-2xl px-4 py-2.5 text-sm leading-relaxed ${
                                            msg.speaker === 'user' 
                                            ? 'bg-blue-600 text-white rounded-br-none' 
                                            : 'bg-gray-100 text-gray-800 rounded-bl-none'
                                        }`}>
                                            {msg.text}
                                        </div>
                                    </div>
                                ))}
                                <div ref={transcriptEndRef} />
                            </div>
                        </div>
                    </div>
                )}
            </main>
        </div>
    );
}

const root = createRoot(document.getElementById('root')!);
root.render(<App />);
